// Import necessary libraries
const Web3 = require('web3');
const { ethers } = require('ethers');

// Initialize web3 instance connected to an Ethereum node
const web3 = new Web3(new Web3.providers.HttpProvider('https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID'));

// Private key for the wallet signing transactions
const privateKey = 'YOUR_PRIVATE_KEY';

// Function to send ETH from one address to another
async function sendEth(fromAddress, toAddress, amount) {
  const account = web3.eth.accounts.privateKeyToAccount(privateKey);
  
  // Check balance before sending
  const balance = await web3.eth.getBalance(account.address);
  console.log(`Current balance: ${balance}`);
  
  // Create transaction object
  const tx = {
    from: fromAddress,
    to: toAddress,
    value: web3.utils.toWei(amount, 'ether'),
    gas: 21000,
    gasPrice: await web3.eth.getGasPrice()
  };

  // Sign and send the transaction
  const signedTx = await web3.eth.accounts.signTransaction(tx, privateKey);
  const receipt = await web3.eth.sendSignedTransaction(signedTx.rawTransaction);
  
  console.log('Transaction receipt:', receipt);
}

// Function to interact with a smart contract (example function: transfer() in ERC20)
async function interactWithSmartContract(contractAddress, abi, fromAddress, recipient, amount) {
  const account = web3.eth.accounts.privateKeyToAccount(privateKey);

  // Create contract instance
  const contract = new web3.eth.Contract(abi, contractAddress, { from: fromAddress });

  // Estimate gas for the transaction
  const gasEstimate = await contract.methods.transfer(recipient, amount).estimateGas();

  // Create and send transaction
  const tx = {
    to: contractAddress,
    data: contract.methods.transfer(recipient, amount).encodeABI(),
    gas: gasEstimate,
    gasPrice: await web3.eth.getGasPrice()
  };

  const signedTx = await web3.eth.accounts.signTransaction(tx, privateKey);
  const receipt = await web3.eth.sendSignedTransaction(signedTx.rawTransaction);

  console.log('Contract interaction receipt:', receipt);
}

